class Solution(object):
    def oddString(self, words):
        def get_diff_array(word):
            return tuple(ord(word[i+1]) - ord(word[i]) for i in range(len(word) - 1))
        diff_map = {}
        for word in words:
            diff = get_diff_array(word)
            diff_map[diff] = diff_map.get(diff, []) + [word]
        for diff, word_list in diff_map.items():
            if len(word_list) == 1:
                return word_list[0]
